#include <cstring>
#include <iostream>

int main()
{
    const int maxLen{ 64 };
    char str1[maxLen];
    char str2[maxLen];

    std::cin.getline(str1, maxLen);
    std::cin.getline(str2, maxLen);

    int cmp{ std::strcmp(str1, str2) };

    if (cmp < 0)
        std::cout << "before\n";
    else if (cmp > 0)
        std::cout << "after\n";
    else
        std::cout << "equal\n";

    char combined[maxLen * 2];
    std::strcpy(combined, str1);
    std::strcat(combined, str2);

    std::cout << std::strlen(combined) << '\n';
    std::cout << combined << '\n';

    return 0;
}
